/* ══════════════════════════════════════════════════════════
   FadeIn
══════════════════════════════════════════════════════════ */
function FadeIn({ children, delay=0, dir="up", style={} }) {
  const ref = useRef(null);
  const [v, setV] = useState(false);
  useEffect(()=>{
    const ob = new IntersectionObserver(([e])=>{ if(e.isIntersecting){setV(true);ob.disconnect();} },{ threshold:0.05 });
    const id = setTimeout(()=>{ if(ref.current) ob.observe(ref.current); },80);
    return ()=>{ clearTimeout(id); ob.disconnect(); };
  },[]);
  const dy = dir==="up"?"24px":dir==="down"?"-24px":"0";
  const dx = dir==="left"?"24px":dir==="right"?"-24px":"0";
  return (
    <div ref={ref} style={{opacity:v?1:0,transform:v?"translate(0,0)":`translate(${dx},${dy})`,transition:`opacity 0.65s ease ${delay}ms, transform 0.65s ease ${delay}ms`,...style}}>
      {children}
    </div>
  );
}

/* ══════════════════════════════════════════════════════════
   Typewriter
══════════════════════════════════════════════════════════ */
function TW({ texts, color }) {
  const [ti,setTi]=useState(0); const [ci,setCi]=useState(0); const [del,setDel]=useState(false); const [txt,setTxt]=useState("");
  useEffect(()=>{
    const cur=texts[ti];
    if(!del&&ci<cur.length){ const id=setTimeout(()=>{setTxt(cur.slice(0,ci+1));setCi(c=>c+1);},60); return()=>clearTimeout(id); }
    if(!del&&ci===cur.length){ const id=setTimeout(()=>setDel(true),2400); return()=>clearTimeout(id); }
    if(del&&ci>0){ const id=setTimeout(()=>{setTxt(cur.slice(0,ci-1));setCi(c=>c-1);},32); return()=>clearTimeout(id); }
    setDel(false); setTi(i=>(i+1)%texts.length);
  },[ci,del,ti,texts]);
  return <span style={{color}}>{txt}<span style={{animation:"blink 1s step-end infinite",color}}>|</span></span>;
}

